import torch
import torch.nn as nn
import torch.nn.utils.prune as prune
import torchvision.models as models

# --- Complete Optimization Pipeline ---

class ModelOptimizer:
    def __init__(self, model):
        self.model = model.eval()

    def count_params(self):
        return sum(p.numel() for p in self.model.parameters())

    def size_mb(self):
        return sum(p.nelement() * p.element_size() for p in self.model.parameters()) / 1024 / 1024

    def prune_conv_layers(self, amount=0.3):
        for module in self.model.modules():
            if isinstance(module, nn.Conv2d):
                prune.ln_structured(module, 'weight', amount=amount, n=2, dim=0)
                prune.remove(module, 'weight')
        return self

    def quantize_dynamic(self):
        self.model = torch.ao.quantization.quantize_dynamic(
            self.model, {nn.Linear}, dtype=torch.qint8
        )
        return self

    def export_onnx(self, path, input_shape=(1, 3, 224, 224)):
        dummy = torch.randn(*input_shape)
        torch.onnx.export(self.model, dummy, path, opset_version=17,
                          input_names=['input'], output_names=['output'])
        return self

# Run pipeline
model = models.resnet50(pretrained=True)
optimizer = ModelOptimizer(model)
print(f"Before: {optimizer.count_params():,} params, {optimizer.size_mb():.1f} MB")

optimizer.prune_conv_layers(0.3).quantize_dynamic()
print(f"After: {optimizer.count_params():,} params, {optimizer.size_mb():.1f} MB")
